    if (a != b && a != c) {
        sum += a;
    }

    // If b is unique, add it to sum
    if (b != a && b != c) {
        sum += b;
    }

    // If c is unique, add it to sum
    if (c != a && c != b) {
        sum += c;
    }

    return sum;
}

