public int sum67(int[] nums) {
    int total = 0;
    boolean inSection = false;

    for (int num : nums) {
        if (num == 6) {
            inSection = true;
        }

        if (!inSection) {
            total += num;
        }

        if (inSection && num == 7) {
            inSection = false;
        }
    }

    return total;
}

