public int sum67(int[] nums) {
    int sum = 0;
    boolean inIgnoringMode = false;

    for (int num : nums) {
        if (num == 6) {
            inIgnoringMode = true;
        }

        if (!inIgnoringMode) {
            sum += num;
        }

        if (num == 7 && inIgnoringMode) {
            inIgnoringMode = false;
        }
    }

    return sum;
}

