Code:
public String alarmClock(int day, boolean vacation) {
    if (day >= 1 && day <= 5) { // Weekdays
        if (vacation) {
            return "10:00";
        } else {
            return "7:00";
        }
    } else { // Weekends (day == 0 or day == 6)
        if (vacation) {
            return "off";
        } else {
            return "10:00";
        }
    }
}

