public int makeChocolate(int small, int big, int goal) {
    int maxBigBars = goal / 5;
    int bigBarsUsed = Math.min(maxBigBars, big);
    int remainingKilos = goal - (bigBarsUsed * 5);
    if (remainingKilos <= small) {
        return remainingKilos;
    } else {
        return -1;
    }
}

